"""
eval/eval_from_generations.py — Batch evaluation of saved .c files (KernelBench-compatible).

Takes C files generated by generate_samples.py (or written by hand) and
evaluates them on the provisioned Arm EC2 instance via SSH.

Mirrors KernelBench's eval_from_generations.py structure.

Usage:
    # Evaluate a single generated file:
    python eval/eval_from_generations.py --input generations/loop_001_sve2_run0.c

    # Evaluate all generations for an ISA:
    python eval/eval_from_generations.py --all --isa sve2

    # Oracle check (should return level=3):
    python eval/eval_from_generations.py --input loops/loop_001.c --problem loop_001 --isa sve2
"""

import argparse
import json
import re
from pathlib import Path

from eval.config import REPO_ROOT, load_problems
from eval.provision import get_or_provision, get_running_instance
from eval.tools import SIMDTools, EvalResult

GENERATIONS_DIR = REPO_ROOT / "generations"
RESULTS_DIR = REPO_ROOT / "results"


def infer_problem_and_isa(path: Path) -> tuple[str, str]:
    """
    Infer problem_id and isa from filename.
    Expected pattern: loop_001_sve2_run0.c or loop_001.c
    """
    stem = path.stem  # e.g. "loop_001_sve2_run0" or "loop_001"
    parts = stem.split("_")
    if len(parts) >= 3:
        problem_id = "_".join(parts[:2])    # "loop_001"
        isa = parts[2]                       # "sve2"
    elif len(parts) == 2:
        problem_id = stem                    # "loop_001"
        isa = "sve2"                         # default
    else:
        raise ValueError(f"Cannot infer problem/ISA from filename: {path.name}")
    return problem_id, isa


def evaluate_file(
    code_path: Path,
    problem_id: str,
    isa: str,
    handle=None,
) -> EvalResult:
    """
    Evaluate a single C file on the Arm instance.

    Args:
        code_path: Path to the .c file containing the candidate implementation.
        problem_id: e.g. "loop_001"
        isa: "neon", "sve", "sve2", or "sme2"
        handle: Optional pre-provisioned InstanceHandle. If None, looks up from config.
    """
    code = code_path.read_text()

    if handle is None:
        handle = get_running_instance(isa)
        if handle is None:
            print(f"[eval] No running instance for ISA={isa}. Provisioning...")
            handle = get_or_provision(isa)

    tools = SIMDTools(handle=handle, problem_id=problem_id, isa=isa)
    return tools.submit(code)


def save_result(problem_id: str, isa: str, result: EvalResult, input_path: Path):
    RESULTS_DIR.mkdir(exist_ok=True)
    out_path = RESULTS_DIR / f"{input_path.stem}_result.json"
    data = result.to_dict()
    data["problem_id"] = problem_id
    data["isa"] = isa
    data["input_file"] = str(input_path)
    out_path.write_text(json.dumps(data, indent=2))
    return out_path


def print_result(problem_id: str, isa: str, result: EvalResult):
    level_labels = {
        0: "FAIL (compile error or wrong checksum)",
        1: "Level 1 — correct",
        2: "Level 2 — correct + faster than scalar",
        3: "Level 3 — correct + faster than autovec",
    }
    label = level_labels.get(result.level, f"Level {result.level}")
    print(f"\n{'─'*50}")
    print(f"  Problem: {problem_id}  ISA: {isa}")
    print(f"  Result:  {label}")
    if result.speedup_vs_scalar is not None:
        print(f"  Speedup vs scalar:  {result.speedup_vs_scalar:.2f}×")
    if result.speedup_vs_autovec is not None:
        print(f"  Speedup vs autovec: {result.speedup_vs_autovec:.2f}×")
    if result.runtime_ms is not None:
        print(f"  Runtime: {result.runtime_ms:.1f} ms (1000 iters)")
    if result.compile_error:
        print(f"  Error: {result.compile_error[:200]}")
    print(f"{'─'*50}")


def main():
    parser = argparse.ArgumentParser(
        description="Evaluate generated SIMD implementations on Arm EC2"
    )
    grp = parser.add_mutually_exclusive_group(required=True)
    grp.add_argument("--input", help="Path to a single .c file to evaluate")
    grp.add_argument("--all", action="store_true",
                     help="Evaluate all files in generations/ for the given ISA")
    parser.add_argument("--isa", choices=["neon", "sve", "sve2", "sme2"],
                        help="ISA target (inferred from filename if not set)")
    parser.add_argument("--problem", help="Problem ID (inferred from filename if not set)")
    parser.add_argument("--no-save", action="store_true", help="Don't save results to results/")
    args = parser.parse_args()

    if args.input:
        path = Path(args.input)
        if not path.exists():
            print(f"File not found: {path}")
            return

        problem_id, isa = infer_problem_and_isa(path)
        if args.problem:
            problem_id = args.problem
        if args.isa:
            isa = args.isa

        handle = get_running_instance(isa)
        if handle is None:
            print(f"Provisioning instance for ISA={isa}...")
            handle = get_or_provision(isa)

        result = evaluate_file(path, problem_id, isa, handle)
        print_result(problem_id, isa, result)
        if not args.no_save:
            out = save_result(problem_id, isa, result, path)
            print(f"  Saved: {out}")

    else:  # --all
        if not args.isa:
            parser.error("--isa is required with --all")

        isa = args.isa
        files = sorted(GENERATIONS_DIR.glob(f"*_{isa}_*.c"))
        if not files:
            print(f"No files found in {GENERATIONS_DIR} matching ISA={isa}")
            return

        print(f"Evaluating {len(files)} files (ISA: {isa})")

        handle = get_running_instance(isa)
        if handle is None:
            print(f"Provisioning instance for ISA={isa}...")
            handle = get_or_provision(isa)

        summary = {"total": len(files), "level": {0: 0, 1: 0, 2: 0, 3: 0}}
        for path in files:
            problem_id, _ = infer_problem_and_isa(path)
            result = evaluate_file(path, problem_id, isa, handle)
            print_result(problem_id, isa, result)
            summary["level"][result.level] = summary["level"].get(result.level, 0) + 1
            if not args.no_save:
                save_result(problem_id, isa, result, path)

        # Print aggregate score (mirrors KernelBench's fast_p)
        n = summary["total"]
        n_correct = sum(v for k, v in summary["level"].items() if k >= 1)
        n_fast = sum(v for k, v in summary["level"].items() if k >= 2)
        n_beats_autovec = summary["level"].get(3, 0)
        print(f"\n{'='*50}")
        print(f"  Benchmark summary — ISA: {isa}")
        print(f"  Total problems:       {n}")
        print(f"  Correct (level ≥ 1):  {n_correct}/{n} ({100*n_correct//n}%)")
        print(f"  Beats scalar (≥ 2):   {n_fast}/{n} ({100*n_fast//n}%)  [fast_p]")
        print(f"  Beats autovec (= 3):  {n_beats_autovec}/{n} ({100*n_beats_autovec//n}%)")
        print(f"{'='*50}")


if __name__ == "__main__":
    main()
